import streamlit as st


def apply_theme() -> None:
    st.markdown("""
<style>
:root{--bg:#090909;--surface:#111111;--surface2:#171717;--gold:#D4AF37;--green:#2ECC71;--red:#E74C3C;--text:#FFFFFF;--muted:#BFBFBF;--line:rgba(212,175,55,.18);--shadow:0 22px 70px rgba(0,0,0,.42)}
*{box-sizing:border-box}html,body,.stApp{max-width:100%;overflow-x:hidden}.stApp{background:radial-gradient(circle at 15% 0,rgba(212,175,55,.14),transparent 30%),radial-gradient(circle at 90% 8%,rgba(212,175,55,.08),transparent 24%),var(--bg);color:var(--text);font-family:Inter,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}.block-container{width:100%!important;max-width:100%!important;padding:6.2rem .9rem 2rem!important}#MainMenu,footer,header,[data-testid="stToolbar"]{display:none!important}.topbar{position:fixed;top:0;left:0;right:0;z-index:9;padding:.85rem .95rem;background:rgba(9,9,9,.88);backdrop-filter:blur(18px);border-bottom:1px solid var(--line)}.brand{width:100%;max-width:1600px;margin:0 auto;display:flex;justify-content:space-between;align-items:center;gap:.75rem}.brand-identity{display:flex;align-items:center;gap:.72rem;min-width:0}.brand-identity span{display:block;font-weight:950;letter-spacing:-.045em;font-size:1.08rem}.brand-identity small{display:block;color:var(--muted);font-size:.72rem;letter-spacing:.01em}.brand-logo{width:38px;height:38px;flex:0 0 38px;filter:drop-shadow(0 0 14px rgba(212,175,55,.24))}.market-time{color:var(--muted);font-size:.76rem;text-align:right;white-space:nowrap}.stSegmentedControl{margin-bottom:1rem}.stSegmentedControl [data-baseweb="button-group"]{display:flex;gap:.45rem;overflow-x:auto;max-width:100%;padding:.25rem 0 .35rem;scrollbar-width:none;background:transparent;border:0}.stSegmentedControl [data-baseweb="button-group"]::-webkit-scrollbar{display:none}.stSegmentedControl button{white-space:nowrap!important;color:var(--muted)!important;font-size:.8rem!important;font-weight:850!important;border:1px solid rgba(255,255,255,.06)!important;border-radius:999px!important;padding:.52rem .82rem!important;background:rgba(17,17,17,.82)!important;min-height:auto!important;transition:all .18s ease!important}.stSegmentedControl button:hover{color:white!important;border-color:rgba(212,175,55,.35)!important;transform:translateY(-1px)}.stSegmentedControl button[aria-pressed="true"]{color:#090909!important;background:linear-gradient(135deg,#FFE8A3,var(--gold))!important;border-color:rgba(212,175,55,.7)!important}.card{min-width:0;border:1px solid var(--line);border-radius:24px;padding:1rem;margin:.75rem 0;background:linear-gradient(145deg,rgba(255,255,255,.055),rgba(255,255,255,.015)),var(--surface);box-shadow:var(--shadow);animation:up .28s ease both;transition:transform .18s ease,border-color .18s ease,box-shadow .18s ease}.card:hover{transform:translateY(-2px);border-color:rgba(212,175,55,.34);box-shadow:0 28px 80px rgba(0,0,0,.5)}.hero{background:radial-gradient(circle at 10% 0,rgba(212,175,55,.23),transparent 42%),linear-gradient(145deg,#191919,#0E0E0E)}h1,h2,h3,p{margin-top:0}h1{font-size:clamp(2.15rem,6vw,4.4rem);line-height:.95;letter-spacing:-.065em}.muted{color:var(--muted);font-size:.86rem}.metric{display:grid;grid-template-columns:1fr;gap:.6rem}.metric div{min-width:0;background:rgba(0,0,0,.24);border:1px solid rgba(255,255,255,.07);border-radius:17px;padding:.72rem .62rem}.metric b{display:block;font-size:.95rem;overflow-wrap:anywhere}.positive{color:var(--green)}.negative{color:var(--red)}.pill{display:inline-flex;border-radius:999px;padding:.32rem .62rem;background:linear-gradient(135deg,#FFE8A3,var(--gold));color:#15110A;font-size:.7rem;font-weight:950}.soft{background:rgba(255,255,255,.055);border:1px solid var(--line);color:white}.row{display:flex;justify-content:space-between;gap:.8rem;align-items:center;min-width:0}.row>*{min-width:0}.logo{width:40px;height:40px;border-radius:50%;flex:0 0 auto}.spark{height:54px;width:100%;margin:.55rem 0}.empty{text-align:left;border-style:dashed}.dashboard-grid{display:grid;grid-template-columns:1fr;gap:.8rem}.dashboard-grid .card{height:100%;margin:0}.dashboard-span-2,.dashboard-span-3{grid-column:auto}.dashboard-section-title{display:flex;justify-content:space-between;align-items:center;gap:.75rem;margin-bottom:.8rem}.mini-list{display:grid;gap:.65rem}.mini-item{padding:.75rem;border:1px solid rgba(255,255,255,.07);border-radius:18px;background:rgba(0,0,0,.2);transition:background .18s ease,border-color .18s ease}.mini-item:hover{background:rgba(212,175,55,.06);border-color:rgba(212,175,55,.24)}.stButton button,.stDownloadButton button{border-radius:17px!important;border:1px solid rgba(212,175,55,.42)!important;background:linear-gradient(135deg,rgba(212,175,55,.24),rgba(255,255,255,.05))!important;color:white!important;min-height:45px;transition:all .18s ease!important}.stButton button:hover,.stDownloadButton button:hover{transform:translateY(-1px);border-color:rgba(212,175,55,.75)!important}.app-footer{margin:1.2rem 0 .3rem;padding:1rem;text-align:center;border-top:1px solid var(--line);color:var(--muted);font-size:.76rem}.app-footer b{display:block;color:var(--gold);font-size:.82rem;margin-bottom:.2rem}.stTextInput input,.stNumberInput input,.stTextArea textarea{border-radius:16px!important;background:rgba(255,255,255,.06)!important;color:white!important;border-color:var(--line)!important}@keyframes up{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:none}}
@media(max-width:420px){.brand{align-items:flex-start}.market-time{font-size:.68rem}.brand-identity small{font-size:.66rem}.block-container{padding-left:.7rem!important;padding-right:.7rem!important}.metric{gap:.42rem}.metric div{padding:.6rem .48rem}}
@media(min-width:768px){.block-container{max-width:100%!important;padding:6.8rem 1.25rem 2.4rem!important}.brand{padding:0 .25rem}.dashboard-grid{grid-template-columns:repeat(2,minmax(0,1fr));gap:1rem}.metric{grid-template-columns:repeat(2,minmax(0,1fr))}.stSegmentedControl [data-baseweb="button-group"]{flex-wrap:wrap;overflow-x:hidden}.card{padding:1.1rem}}
@media(min-width:1180px){.block-container{max-width:1600px!important;padding:6.2rem 1.5rem 2.8rem 15.5rem!important}.topbar{padding-left:1.5rem;padding-right:1.5rem}.dashboard-grid{grid-template-columns:repeat(3,minmax(0,1fr));gap:1.15rem}.dashboard-span-2{grid-column:span 2}.dashboard-span-3{grid-column:span 3}.metric{grid-template-columns:repeat(3,minmax(0,1fr))}.stSegmentedControl{position:fixed;z-index:8;left:1.5rem;top:6.2rem;width:12.5rem;margin:0;padding:1rem;border:1px solid var(--line);border-radius:24px;background:rgba(17,17,17,.88);backdrop-filter:blur(16px);box-shadow:var(--shadow)}.stSegmentedControl:before{content:'Navigation';display:block;color:var(--gold);font-weight:900;margin:0 0 .8rem .2rem;letter-spacing:.02em}.stSegmentedControl [data-baseweb="button-group"]{display:grid;grid-template-columns:1fr;gap:.5rem;padding:0}.stSegmentedControl button{width:100%!important;justify-content:flex-start!important;border-radius:15px!important;font-size:.82rem!important}.card{padding:1.2rem}}
</style>""", unsafe_allow_html=True)
